2. using System.Collections.Concurrent;
3. using ContosoUniversity.Models;
4. 
5. namespace ContosoUniversity.Services
6. {
7.     public class NotificationService : IDisposable
8.     {
9.         // Static shared queue across application instances (simple in-memory alternative to MSMQ)
10.         private static readonly ConcurrentQueue<Notification> _queue = new();
11.         private static readonly int _maxQueueLength = 500; // basic cap to prevent unbounded growth
12. 
13.         public NotificationService()
14.         {
15.             // No initialization required for in-memory queue
16.         }
17. 
18.         public void SendNotification(string entityType, string entityId, EntityOperation operation, string userName = null)
19.         {
20.             SendNotification(entityType, entityId, null, operation, userName);
21.         }
22. 
23.         public void SendNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation, string userName = null)
24.         {
25.             try
26.             {
27.                 var notification = new Notification
28.                 {
29.                     EntityType = entityType,
30.                     EntityId = entityId,
31.                     Operation = operation.ToString(),
32.                     Message = GenerateMessage(entityType, entityId, entityDisplayName, operation),
33.                     CreatedAt = DateTime.Now,
34.                     CreatedBy = userName ?? "System",
35.                     IsRead = false
36.                 };
37. 
38.                 _queue.Enqueue(notification);
39. 
40.                 // Enforce max queue length (best-effort)
41.                 while (_queue.Count > _maxQueueLength && _queue.TryDequeue(out _)) { }
42.             }
43.             catch (Exception ex)
44.             {
45.                 System.Diagnostics.Debug.WriteLine($"Failed to enqueue notification: {ex.Message}");
46.             }
47.         }
48. 
49.         public Notification ReceiveNotification()
50.         {
51.             try
52.             {
53.                 return _queue.TryDequeue(out var notification) ? notification : null;
54.             }
55.             catch (Exception ex)
56.             {
57.                 System.Diagnostics.Debug.WriteLine($"Failed to receive notification: {ex.Message}");
58.                 return null;
59.             }
60.         }
61. 
62.         public void MarkAsRead(int notificationId)
63.         {
64.             // No-op for in-memory implementation (persistence not implemented)
65.         }
66. 
67.         private string GenerateMessage(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
68.         {
69.             var displayText = !string.IsNullOrWhiteSpace(entityDisplayName)
70.                 ? $"{entityType} '{entityDisplayName}'"
71.                 : $"{entityType} (ID: {entityId})";
72. 
73.             return operation switch
74.             {
75.                 EntityOperation.CREATE => $"New {displayText} has been created",
76.                 EntityOperation.UPDATE => $"{displayText} has been updated",
77.                 EntityOperation.DELETE => $"{displayText} has been deleted",
78.                 _ => $"{displayText} operation: {operation}"
79.             };
80.         }
81. 
82.         public void Dispose()
83.         {
84.             // Nothing to dispose for in-memory queue
85.         }
86.     }
87. }
