using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any residual messages from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
    }

    [TestMethod]
    public void SendNotification_CreateWithDisplayName_EnqueuesCorrectNotification()
    {
        _sut.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "Admin");

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student 'John Smith' has been created", notification.Message);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_CreateWithoutDisplayName_UsesIdInMessage()
    {
        _sut.SendNotification("Course", "42", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesUpdateMessage()
    {
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.UPDATE, "System");

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("Department 'Engineering' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
    {
        _sut.SendNotification("Instructor", "3", "Dr. Smith", EntityOperation.DELETE, "Admin");

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("DELETE", notification.Operation);
        Assert.AreEqual("Instructor 'Dr. Smith' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NoUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToNow()
    {
        var before = DateTime.Now.AddSeconds(-1);

        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var after = DateTime.Now.AddSeconds(1);
        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before, $"CreatedAt {notification.CreatedAt} should be >= {before}");
        Assert.IsTrue(notification.CreatedAt <= after, $"CreatedAt {notification.CreatedAt} should be <= {after}");
    }

    [TestMethod]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        var notification = _sut.ReceiveNotification();
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsInFifoOrder()
    {
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", EntityOperation.DELETE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        Assert.AreEqual("A", first.EntityType);
        Assert.AreEqual("B", second.EntityType);
        Assert.AreEqual("C", third.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_RemovesFromQueue()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void SendNotification_MultipleMessages_AllEnqueued()
    {
        for (int i = 0; i < 5; i++)
        {
            _sut.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        int count = 0;
        while (_sut.ReceiveNotification() != null)
        {
            count++;
        }

        Assert.AreEqual(5, count);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
        // No exception means pass
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        service.Dispose();
        // No exception means pass
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
    {
        _sut.SendNotification("Student", "1", "", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
    {
        _sut.SendNotification("Student", "1", "   ", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        var items = new List<int> { 1, 2, 3 };
        var list = new PaginatedList<int>(items, 10, 2, 3);
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPages()
    {
        var items = new List<int> { 1, 2, 3 };
        var list = new PaginatedList<int>(items, 10, 1, 3);
        Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<int> { 10, 20, 30 };
        var list = new PaginatedList<int>(items, 10, 1, 3);

        Assert.AreEqual(3, list.Count);
        Assert.AreEqual(10, list[0]);
        Assert.AreEqual(20, list[1]);
        Assert.AreEqual(30, list[2]);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
    [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 = 3 pages")]
    [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 = 1 page")]
    [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 = 0 pages")]
    [DataRow(20, 10, 2, DisplayName = "20 items, page size 10 = 2 pages")]
    public void TotalPages_CalculatedCorrectly(int totalCount, int pageSize, int expectedPages)
    {
        var list = new PaginatedList<int>(new List<int>(), totalCount, 1, pageSize);
        Assert.AreEqual(expectedPages, list.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 5);
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 4, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_FirstPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_OnlyOnePage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 5);

        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 13).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 5);

        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(13, result[2]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
    }

    [TestMethod]
    public void Create_SingleItemSource_ReturnsSingleItem()
    {
        var source = new[] { 42 }.AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(42, result[0]);
        Assert.AreEqual(1, result.TotalPages);
    }

    [TestMethod]
    public void PaginatedList_InheritsFromList()
    {
        var list = new PaginatedList<string>(new List<string> { "a", "b" }, 2, 1, 10);
        Assert.IsInstanceOfType<List<string>>(list);
    }
}

