    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateContext();
        _controller = new StudentsController(_context);
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_DefaultSort_ReturnsStudentsOrderedByLastName()
    {
        _context.Students.AddRange(
            TestHelpers.CreateTestStudent("Charlie", "Zulu"),
            TestHelpers.CreateTestStudent("Alice", "Alpha"),
            TestHelpers.CreateTestStudent("Bob", "Mike")
        );
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
