        var course = TestHelpers.CreateTestCourse(2001, "Physics", 4, dept.DepartmentID);
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns($"test{extension}");
        mockFile.Setup(f => f.Length).Returns(1024);
        mockFile.Setup(f => f.CopyTo(It.IsAny<System.IO.Stream>()));

        _controller.Create(course, mockFile.Object);

        // Should not have extension error (may have other issues in test env but not extension validation)
        var extensionErrors = _controller.ModelState
            .Where(kvp => kvp.Key == "teachingMaterialImage")
            .SelectMany(kvp => kvp.Value.Errors)
            .Where(e => e.ErrorMessage.Contains("valid image file"));
        Assert.AreEqual(0, extensionErrors.Count());
    }

