using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context;
    private HomeController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateContext();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void About_ReturnsViewWithEnrollmentDateGroups()
    {
        _context.Students.AddRange(
            TestHelpers.CreateTestStudent("A", "A", new DateTime(2023, 9, 1)),
            TestHelpers.CreateTestStudent("B", "B", new DateTime(2023, 9, 1)),
            TestHelpers.CreateTestStudent("C", "C", new DateTime(2022, 9, 1))
        );
        _context.SaveChanges();

        var result = _controller.About() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var group2023 = model.Single(g => g.EnrollmentDate == new DateTime(2023, 9, 1));
        Assert.AreEqual(2, group2023.StudentCount);

        var group2022 = model.Single(g => g.EnrollmentDate == new DateTime(2022, 9, 1));
        Assert.AreEqual(1, group2022.StudentCount);
    }

    [TestMethod]
    public void About_EmptyDatabase_ReturnsEmptyList()
    {
        var result = _controller.About() as ViewResult;

        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Contact_ReturnsView()
    {
        var result = _controller.Contact() as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        _controller.Contact();
        Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsView()
    {
        var result = _controller.Error() as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsView()
    {
        var result = _controller.Unauthorized() as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Unauthorized_SetsViewBagMessage()
    {
        _controller.Unauthorized();
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using System;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateContext();
        _controller = new NotificationsController(_context);
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        var json = result.Value as dynamic;
        Assert.IsNotNull(json);
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Enqueue some notifications via the service
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John", EntityOperation.CREATE);
        service.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10Notifications()
    {
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        // After retrieving, queue should still have remaining items
        // The method limits to 10 max
    }

    [TestMethod]
    public void MarkAsRead_ReturnsJsonResult()
    {
        var result = _controller.MarkAsRead(1);

        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
    }

    [TestMethod]
    public void MarkAsRead_WithValidId_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(42);

        Assert.IsNotNull(result);
        // MarkAsRead is a no-op in the in-memory implementation
        // but should still return a success response
    }
}

