[TestClass]
public sealed class SchoolContextTests
{
    [TestMethod]
    public void SchoolContext_CanCreateInstance()
    {
        var context = TestHelpers.CreateContext();
        Assert.IsNotNull(context);
    }

    [TestMethod]
    public void SchoolContext_DbSetsAreNotNull()
    {
        var context = TestHelpers.CreateContext();

        Assert.IsNotNull(context.Students);
        Assert.IsNotNull(context.Instructors);
        Assert.IsNotNull(context.Courses);
        Assert.IsNotNull(context.Departments);
        Assert.IsNotNull(context.Enrollments);
        Assert.IsNotNull(context.OfficeAssignments);
        Assert.IsNotNull(context.CourseAssignments);
        Assert.IsNotNull(context.People);
        Assert.IsNotNull(context.Notifications);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveStudent()
    {
        var context = TestHelpers.CreateContext();
        var student = TestHelpers.CreateTestStudent("Test", "User");
        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.Find(student.ID);
        Assert.IsNotNull(retrieved);
        Assert.AreEqual("Test", retrieved.FirstMidName);
        Assert.AreEqual("User", retrieved.LastName);
    }

    [TestMethod]
    public void SchoolContext_CourseAssignment_HasCompositeKey()
    {
        var context = TestHelpers.CreateContext();

        var instructor = TestHelpers.CreateTestInstructor("Test", "Inst");
        context.Instructors.Add(instructor);

        var dept = TestHelpers.CreateTestDepartment();
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = TestHelpers.CreateTestCourse(5001, "Test", 3, dept.DepartmentID);
        context.Courses.Add(course);
        context.SaveChanges();

        var ca = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
        context.CourseAssignments.Add(ca);
        context.SaveChanges();

        var found = context.CourseAssignments.Find(course.CourseID, instructor.ID);
        Assert.IsNotNull(found);
        Assert.AreEqual(instructor.ID, found.InstructorID);
        Assert.AreEqual(course.CourseID, found.CourseID);
    }

    [TestMethod]
    public void SchoolContext_StudentAndInstructor_SharePersonTable()
    {
        var context = TestHelpers.CreateContext();
        context.Students.Add(TestHelpers.CreateTestStudent("S", "Student"));
        context.Instructors.Add(TestHelpers.CreateTestInstructor("I", "Instructor"));
        context.SaveChanges();

        // Both should appear in the People DbSet (TPH)
        Assert.AreEqual(2, context.People.Count());
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveNotification()
    {
        var context = TestHelpers.CreateContext();
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test notification",
            CreatedAt = DateTime.Now,
            CreatedBy = "System",
            IsRead = false
        };
        context.Notifications.Add(notification);
        context.SaveChanges();

        var retrieved = context.Notifications.Find(notification.Id);
        Assert.IsNotNull(retrieved);
        Assert.AreEqual("Student", retrieved.EntityType);
        Assert.AreEqual("CREATE", retrieved.Operation);
    }

    [TestMethod]
    public void SchoolContext_InstructorOfficeAssignment_OneToOne()
    {
        var context = TestHelpers.CreateContext();
        var instructor = TestHelpers.CreateTestInstructor("Test", "Prof");
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var office = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 42" };
        context.OfficeAssignments.Add(office);
        context.SaveChanges();

        var retrieved = context.OfficeAssignments.Find(instructor.ID);
        Assert.IsNotNull(retrieved);
        Assert.AreEqual("Room 42", retrieved.Location);
    }
}

